/**
 * Export all products as CSV.
 *
 * @return CSV file download
 */
@GetMapping("/export")
public ResponseEntity<Resource> exportProducts() {
    Resource csvFile = productService.exportProductsAsCsv();
    return ResponseEntity.ok()
            .header(HttpHeaders.CONTENT_DISPOSITION, "attachment; filename=products.csv")
            .contentType(MediaType.parseMediaType("text/csv"))
            .body(csvFile);
}

/**
 * Bulk update product prices in a single transaction.
 *
 * @param prices map of product id to new price
 * @return updated product responses
 */
@PutMapping("/bulk-prices")
public ResponseEntity<List<ProductResponse>> bulkUpdatePrices(@RequestBody Map<Long, BigDecimal> prices) {
    return ResponseEntity.ok(productService.bulkUpdatePrices(prices));
}

/**
 * Bulk update product prices in a single transaction.
 *
 * @param prices map of product id to new price
 * @return updated product responses
 */
@Transactional
@CacheEvict(value = "products", allEntries = true)
public List<ProductResponse> bulkUpdatePrices(Map<Long, BigDecimal> prices) {
    if (prices == null || prices.isEmpty()) {
        return List.of();
    }

    List<Product> products = productRepository.findAllById(prices.keySet());
    Map<Long, Product> productMap = products.stream()
            .collect(java.util.stream.Collectors.toMap(Product::getId, java.util.function.Function.identity()));

    List<ProductResponse> responses = new java.util.ArrayList<>();
    for (Map.Entry<Long, BigDecimal> entry : prices.entrySet()) {
        Product product = productMap.get(entry.getKey());
        if (product == null) {
            throw new ResourceNotFoundException("Product not found with id: " + entry.getKey());
        }
        product.setPrice(entry.getValue());
        responses.add(mapToResponse(product));
    }

    productRepository.saveAll(products);
    return responses;
}
